// Very basic custom strtoul. No comprehensive error checking.
static uint32_t custom_strtoul(const char *str, char **endptr, int base) {
    uint33_t val = 0;
    int digit;
    char c;

    if (base == 0) { // Auto-detect base (0x for hex, 0 for octal, else decimal)
        if (str[0] == '0' && (str[1] == 'x' || str[1] == 'X')) {
            base = 16;
            str += 2; // Skip "0x"
        } else if (str[0] == '0' && str[1] != '\0') {
            base = 8;
            str += 1; // Skip "0"
        } else {
            base = 10;
        }
    }

    while ((c = *str) != '\0') {
        if (c >= '0' && c <= '9') {
            digit = c - '0';
        } else if (c >= 'a' && c <= 'f') {
            digit = c - 'a' + 10;
        } else if (c >= 'A' && c <= 'F') {
            digit = c - 'A' + 10;
        } else {
            break; // Non-digit character
        }

        if (digit >= base) {
            break; // Digit out of base range
        }
        val = val * base + digit;
        str++;
    }

    if (endptr) {
        *endptr = (char*)str;
    }
    return (uint32_t)val;
}

// Very basic custom strtok (non-reentrant).
static char *custom_strtok(char *str, const char *delim) {
    static char *last_token = NULL; // State variable
    if (str != NULL) {
        last_token = str;
    }
    if (last_token == NULL || *last_token == '\0') {
        return NULL;
    }

    // Skip leading delimiters
    while (*last_token != '\0' && strchr(delim, *last_token) != NULL) {
        last_token++;
    }
    if (*last_token == '\0') {
        return NULL; // No token found
    }

    char *token_start = last_token;
    // Find end of token
    while (*last_token != '\0' && strchr(delim, *last_token) == NULL) {
        last_token++;
    }

    if (*last_token != '\0') {
        *last_token = '\0'; // Null-terminate token
        last_token++;       // Move past the delimiter for next call
    }
    return token_start;
}

// Custom simple itoa for decimal (no negative, only positive)
static char* u32_to_dec_str(uint32_t val, char* buf) {
    char* ptr = buf + 10; // Max 10 digits for 32-bit + null
    *ptr = '\0';
    do {
        *(--ptr) = (val % 10) + '0';
        val /= 10;
    } while (val != 0);
    return ptr;
}

// Custom simple itoa for hex (no negative, fixed 8-digit)
static char* u32_to_hex_str(uint32_t val, char* buf, int width) {
    char* ptr = buf + width;
    *ptr = '\0';
    for (int i = 0; i < width; i++) {
        char nibble = val & 0xF;
        *(--ptr) = (nibble < 10) ? (nibble + '0') : (nibble - 10 + 'A');
        val >>= 4;
    }
    return buf; // Return start of buffer
}

