        console_puts("\r\n");

        console_puts("  Calibration Factor: ");
        console_puts(u32_to_dec_str(current_config.calibration_factor_scaled / 100, temp_buf));
        console_putc('.');
        console_puts(u32_to_dec_str(current_config.calibration_factor_scaled % 100, temp_buf));
