void debug_shell_process(void) {
    static char line_buffer[SHELL_MAX_LINE_LENGTH];
    char* argv[SHELL_MAX_ARGS];
    int argc = 0;

    console_read_line(line_buffer, SHELL_MAX_LINE_LENGTH);

    // Parse command and arguments
    char* token = custom_strtok(line_buffer, " ");
    while (token != NULL && argc < SHELL_MAX_ARGS) {
        argv[argc++] = token;
        token = custom_strtok(NULL, " ");
    }

    if (argc == 0) {
        return; // Empty line
    }

    const char* command = argv[0];

    if (strcmp(command, "help") == 0) {
        help_command();
    } else if (strcmp(command, "dump_memory") == 0) {
        if (argc == 3) {
            uint32_t addr = custom_strtoul(argv[1], NULL, 0);
            size_t len = (size_t)custom_strtoul(argv[2], NULL, 0);
            dump_memory_impl(addr, len);
        } else {
            console_puts("Usage: dump_memory <address> <length>\r\n");
        }
    } else if (strcmp(command, "read_flash") == 0) {
        if (argc == 3) {
            uint32_t addr = custom_strtoul(argv[1], NULL, 0);
            size_t len = (size_t)custom_strtoul(argv[2], NULL, 0);
            read_flash_impl(addr, len);
        } else {
            console_puts("Usage: read_flash <address> <length>\r\n");
        }
    } else if (strcmp(command, "get_config") == 0) {
        if (argc == 2) {
            get_config_impl(argv[1]);
        } else {
            console_puts("Usage: get_config <item>\r\n");
            console_puts("  e.g., get_config all\r\n");
        }
    } else if (strcmp(command, "reboot") == 0) {
        console_puts("Rebooting device...\r\n");
        // This is highly MCU-specific. For ARM Cortex-M:
        // SCB->AIRCR = 0x05FA0004UL; // VECTKEY | SYSRESETREQ
        // Replace with your MCU's specific reset mechanism (e.g., watchdog reset).
        while (1); // Trap here if reset doesn't occur immediately
    }
    else {
        console_puts("Unknown command: ");
        console_puts(command);
        console_puts("\r\nType 'help' for a list of commands.\r\n");
    }
}


